### 生命週期 hooks

```js
import {
  onMounted, onUnmounted, onUpdated,
  onBeforeMount, onBeforeUnmount, onBeforeUpdate
} from "vue";

onMounted(() => {
  console.log("元件掛載");
  // 抓資料、設 timer、訂閱事件
