### SSR / SSG / Hybrid

```ts
// nuxt.config.ts
export default defineNuxtConfig({
  // 全站 SSR（預設）
  ssr: true,

  // 或：混合模式
  routeRules: {
    "/blog/**": { static: true },         // 部落格用 SSG
    "/dashboard": { ssr: false },         // 後台用 SPA
