## 為什麼是 Pinia
- Vuex 太繁瑣（mutation / action / module）
- Pinia 簡化：直接寫 state + action
- TS 自動推斷
- Devtools 整合
- SSR 友善

## 安裝
```bash
npm install pinia
```

```javascript
// main.ts
import { createPinia } from "pinia";
import App from "./App.vue";

const app = createApp(App);
app.use(createPinia());
app.mount("#app");
```

## 定義 Store
```typescript
// stores/user.ts
import { defineStore } from "pinia";
import { ref, computed } from "vue";

export const useUserStore = defineStore("user", () => {
  // state
  const name = ref("");
  const xp = ref(0);

  // getter（computed）
  const level = computed(() => Math.floor(Math.sqrt(xp.value / 100)) + 1);

  // action
  function addXp(amount: number) {
    xp.value += amount;
  }

  async function fetchUser(id: string) {
    const res = await fetch(`/api/users/${id}`);
    const data = await res.json();
    name.value = data.name;
    xp.value = data.xp;
  }

  return { name, xp, level, addXp, fetchUser };
});
```

## 在 component 使用
```vue
<script setup>
import { useUserStore } from "@/stores/user";
const user = useUserStore();

user.addXp(100);
console.log(user.level);  // computed

// 監聽 store 變化
user.$subscribe((mutation, state) => {
  console.log("changed:", state);
});
</script>

<template>
  <div>{{ user.name }} - Lv {{ user.level }}</div>
  <button @click="user.addXp(10)">+10 XP</button>
</template>
```

## 取多個 state（避免失去響應性）
```javascript
import { storeToRefs } from "pinia";

const user = useUserStore();
const { name, xp, level } = storeToRefs(user);  // 保持響應
const { addXp } = user;  // action 直接取
```

❌ 解構：`const { name } = user` → 失去響應性。

## 模組化
- 一個 store 一個檔案：`stores/user.ts`, `stores/cart.ts`
- store 之間可互相 call

## Persistence（自動存 localStorage）
```bash
npm install pinia-plugin-persistedstate
```

```javascript
import { createPinia } from "pinia";
import piniaPluginPersistedstate from "pinia-plugin-persistedstate";

const pinia = createPinia();
pinia.use(piniaPluginPersistedstate);
```

```typescript
export const useUserStore = defineStore("user", () => {
  // ...
}, {
  persist: true,  // 自動存 localStorage
});
```

## SSR 友善
Nuxt 3 內建 Pinia 支援、`useUserStore()` 在 server / client 都能用。

